const raw = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;
if (!body.job_id) throw new Error('Payload missing: job_id');
if (!Array.isArray(body.clip_prompts) || body.clip_prompts.length < 1) throw new Error('Payload must have clip_prompts array');
return [{ json: {
  job_id: body.job_id,
  topic: body.topic,
  title: body.title,
  hashtags: body.hashtags,
  narration: body.narration,
  clip_prompts: body.clip_prompts,
  audio_path: body.audio_path,
  subs_path: body.subs_path,
  audio_duration: body.audio_duration,
  subtitle_chunks: body.subtitle_chunks,
  word_timings: body.word_timings,
  sheet_row: body.sheet_row || null,
  start_time: body.start_time || Date.now(),
  bgm_path: body.bgm_path || null,
  negative_prompts: body.negative_prompts || [],
  highlight_keywords: body.highlight_keywords || [],
  scenes: body.scenes || []
} }];

const { execSync } = require('child_process');
const fs = require('fs');

const items = $input.all().map(item => item.json);

const n8nIn  = '/data/ffmpeg/input';
const n8nOut = '/data/ffmpeg/output';
const contIn = '/ffmpeg/input';
const contOut= '/ffmpeg/output';

if (!fs.existsSync(n8nIn))  fs.mkdirSync(n8nIn,  { recursive: true });
if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

function run(cmd, timeoutMs) {
  const t = timeoutMs || 120000;
  console.log('CMD: ' + cmd.slice(0, 200));
  let out = '';
  try { out = execSync(cmd, { encoding: 'utf-8', timeout: t }); }
  catch(e) { out = (e.stdout || '') + (e.stderr || ''); }
  return out.toString();
}

function assembleOne(data) {
  const jobId = data.job_id;
  const videoPaths = data.video_paths;
  const N = videoPaths.length;
  if (N < 2) throw new Error('Job ' + jobId + ': need at least 2 clips for assembly, got ' + N);
  for (let i = 0; i < N; i++) {
    const diskPath = videoPaths[i].replace('/ffmpeg/input', '/data/ffmpeg/input');
    if (!fs.existsSync(diskPath)) throw new Error('Job ' + jobId + ': clip ' + i + ' missing before assembly: ' + videoPaths[i]);
  }

  for (let i = 0; i < N; i++) {
    run('docker exec qpc_ffmpeg_runner ffmpeg -y -i "' + videoPaths[i] + '" -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" -r 24 -c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p -an "' + contIn + '/' + jobId + '_clip' + i + '_norm.mp4"', 120000);
  }

  let withTransitions;
  if (N === 1) {
    withTransitions = contIn + '/' + jobId + '_clip0_norm.mp4';
  } else {
    const inputs = Array.from({length:N}, (_,i) => '-i "' + contIn + '/' + jobId + '_clip' + i + '_norm.mp4"').join(' ');
    let xf = '';
    let prev = '[0:v]';
    for (let i = 1; i < N; i++) {
      const o = (i === N-1) ? '[vout]' : '[x'+i+']';
      xf += prev + '['+i+':v]xfade=transition=fade:duration=0.3:offset=' + (i*4.7).toFixed(1) + o + ';';
      prev = o;
    }
    run('docker exec qpc_ffmpeg_runner ffmpeg -y ' + inputs + ' -filter_complex "' + xf.slice(0,-1) + '" -map "[vout]" -c:v libx264 -crf 20 -preset fast -pix_fmt yuv420p "' + contIn + '/' + jobId + '_xfade.mp4"', 300000);
    withTransitions = contIn + '/' + jobId + '_xfade.mp4';
  }

  const hlWords = (data.highlight_keywords || []).map(w => w.toLowerCase());
  function esc(s) { return s.replace(/[.+?^${}()|[\]\\*]/g, '\\$&'); }
  function addHighlights(text) {
    let r = text;
    hlWords.forEach(word => {
      const re = new RegExp('(' + esc(word) + ')', 'gi');
      var _bs = String.fromCharCode(92); r = r.replace(re, '{' + _bs + 'c&HFF9600&}$1{' + _bs + 'c&HFFFFFF&}');
    });
    return r;
  }
  const narTxt = (data.narration || '').replace(/_/g, ' ').replace(/\s*-\s*/g, ' ').replace(/"/g, "'").replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
  const hlText = addHighlights(narTxt);
  const totalDur = data.audio_duration || (N * 4.7);
  function secToAss(s) {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sec = Math.floor(s % 60);
    const cs = Math.round((s % 1) * 100);
    return h + ':' + String(m).padStart(2,'0') + ':' + String(sec).padStart(2,'0') + '.' + String(cs).padStart(2,'0');
  }

  const assContent =
    '[Script Info]\nScriptType: v4.00+\nPlayResX: 1080\nPlayResY: 1920\n\n' +
    '[V4+ Styles]\n' +
    'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding\n' +
    'Style: Caption,Liberation Sans,52,&H00FFFFFF,&H000000FF,&H00000000,&H80000000,-1,0,1,3,0,7,60,60,470,1\n\n' +
    '[Events]\nFormat: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n' +
    'Dialogue: 0,0:00:00.00,' + secToAss(totalDur) + ',Caption,,0,0,0,,' + hlText + '\n';

  fs.writeFileSync(n8nIn + '/' + jobId + '.ass', assContent, 'utf8');
  console.log('Job ' + jobId + ': ASS written. Highlights: ' + hlWords.join(', '));

  const logoPath = '/ffmpeg/config/icon/logo.png';
  const tickPath = '/ffmpeg/config/icon/Blue verification badge emblem.png';
  const bgmDir   = '/ffmpeg/config/bgm';

  const hasLogo = run('docker exec qpc_ffmpeg_runner test -f "' + logoPath + '" && echo OK').includes('OK');
  const hasTick = run('docker exec qpc_ffmpeg_runner test -f "' + tickPath + '" && echo OK').includes('OK');

  let narFile = null;
  if (data.audio_path) {
    narFile = data.audio_path.replace('/data/ffmpeg', '/ffmpeg');
    if (!run('docker exec qpc_ffmpeg_runner test -f "' + narFile + '" && echo OK').includes('OK')) {
      console.log('Job ' + jobId + ': narration not found: ' + narFile);
      narFile = null;
    }
  }

  let bgmFile = data.bgm_path ? data.bgm_path.replace('/data/ffmpeg', '/ffmpeg') : null;
  if (!bgmFile) {
    const ls = run('docker exec qpc_ffmpeg_runner ls "' + bgmDir + '" 2>/dev/null').split('\n');
    const mp3 = ls.find(f => f.trim().endsWith('.mp3'));
    if (mp3) bgmFile = bgmDir + '/' + mp3.trim();
  }
  const hasBgm = !!(bgmFile && run('docker exec qpc_ffmpeg_runner test -f "' + bgmFile + '" && echo OK').includes('OK'));
  console.log('Job ' + jobId + ': narFile=' + narFile + ' hasBgm=' + hasBgm);

  const inp   = ['-i "' + withTransitions + '"'];
  const logoI = hasLogo ? inp.push('-i "' + logoPath + '"') - 1 : -1;
  const tickI = hasTick ? inp.push('-i "' + tickPath + '"') - 1 : -1;
  const narI  = narFile  ? inp.push('-i "' + narFile  + '"') - 1 : -1;
  const bgmI  = hasBgm   ? inp.push('-i "' + bgmFile  + '"') - 1 : -1;

  let lbl = 0;
  let vf  = '';
  let cur = '0:v';

  if (hasLogo) {
    vf += '[' + logoI + ':v]scale=110:110,format=rgba[lg];[' + cur + '][lg]overlay=x=40:y=293:format=auto[vb' + lbl + ']';
    cur = 'vb' + lbl; lbl++;
  }

  vf += (vf ? ';' : '') + '[' + cur + "]drawtext=text='SchrodingersCat':fontcolor=white:fontsize=52:x=178:y=308:bordercolor=black:borderw=3[vb" + lbl + ']';
  cur = 'vb' + lbl; lbl++;

  if (hasTick) {
    vf += ';[' + tickI + ":v]crop='min(iw,ih)':'min(iw,ih)',scale=72:72,format=rgba[tk];[" + cur + '][tk]overlay=x=600:y=300:format=auto[vb' + lbl + ']';
    cur = 'vb' + lbl; lbl++;
  }

  vf += ';[' + cur + "]drawtext=text='@SchrodingersCat':fontcolor=white:fontsize=34:x=178:y=377:bordercolor=black:borderw=2[vb" + lbl + ']';
  cur = 'vb' + lbl; lbl++;

  vf += ";[" + cur + "]subtitles=filename='" + contIn + '/' + jobId + ".ass'[outv]";

  let afilters = '';
  let amap     = '-an';

  if (narFile && hasBgm) {
    afilters = ';[' + narI + ':a]volume=1.0[nar];[' + bgmI + ':a]volume=0.25[bgm];[nar][bgm]amix=inputs=2:duration=first:dropout_transition=2[aout]';
    amap     = '-map "[aout]"';
  } else if (narFile) {
    afilters = ';[' + narI + ':a]aformat=sample_fmts=fltp[aout]';
    amap     = '-map "[aout]"';
  } else if (hasBgm) {
    afilters = ';[' + bgmI + ':a]volume=0.85[aout]';
    amap     = '-map "[aout]"';
  }

  const fullFilter = vf + afilters;
  const dur = data.audio_duration ? Math.ceil(data.audio_duration) + 2 : 30;
  const hasAudio = amap !== '-an';

  const cmd =
    'docker exec qpc_ffmpeg_runner ffmpeg -y ' + inp.join(' ') +
    ' -filter_complex "' + fullFilter + '" -map "[outv]" ' + amap +
    ' -c:v libx264 -crf 18 -preset fast -pix_fmt yuv420p -movflags +faststart' +
    (hasAudio ? ' -c:a aac -b:a 192k' : '') +
    ' -t ' + dur + ' "' + contOut + '/' + jobId + '_final.mp4" && echo FINAL_OK';

  const result = run(cmd, 900000);
  if (!result.includes('FINAL_OK')) throw new Error('Job ' + jobId + ': final render failed: ' + result.slice(-800));

  const finalPath = n8nOut + '/' + jobId + '_final.mp4';
  if (!fs.existsSync(finalPath)) throw new Error('Job ' + jobId + ': output missing: ' + finalPath);

  return Object.assign({}, data, { final_video_path: finalPath, output_filename: jobId + '_final.mp4' });
}

console.log('Assembling ' + items.length + ' video(s)...');
const results = items.map(assembleOne);
return results.map(r => ({ json: r }));

const fs = require('fs');
const items = $input.all().map(item => item.json);

return items.map(item => {
  const filePath = item.final_video_path;
  if (!fs.existsSync(filePath)) throw new Error('Final video not found: ' + filePath);
  const b64 = fs.readFileSync(filePath).toString('base64');
  return {
    json: item,
    binary: {
      data: {
        data:          b64,
        mimeType:      'video/mp4',
        fileName:      item.output_filename,
        fileExtension: 'mp4'
      }
    }
  };
});

const permResults = $input.all();
const assembleResults = $('Assemble Video').all();
const uploadResults = $('Upload Animation to Drive').all();

return permResults.map((_, i) => {
  const assemble = assembleResults[i].json;
  const upload = uploadResults[i].json;
  const fileId = upload.id;
  const videoUrl = 'https://drive.usercontent.google.com/download?id=' + fileId + '&export=download';
  const renderTimeSec = Math.round((Date.now() - assemble.start_time) / 1000);
  console.log('Stage 2 complete. Job: ' + assemble.job_id + ', Drive file: ' + fileId + ', Time: ' + renderTimeSec + 's');
  return { json: {
    job_id: assemble.job_id,
    topic: assemble.topic,
    title: assemble.title,
    narration: assemble.narration,
    hashtags: assemble.hashtags,
    final_video_path: assemble.final_video_path,
    output_filename: assemble.output_filename,
    video_url: videoUrl,
    drive_file_id: fileId,
    render_time_seconds: renderTimeSec,
    sheet_row: assemble.sheet_row,
    rowIndex: assemble.rowIndex,
    readyForVideoAt: assemble.readyForVideoAt,
    status: 'stage2_complete'
  }};
});

const stage2Results = $('Stage 2 Done').all();
return stage2Results.map(item => {
  const d = item.json;
  return { json: {
    job_id:           d.job_id,
    title:            d.title,
    topic:            d.topic,
    narration:        d.narration || '',
    description:      (d.narration || d.topic).slice(0, 500),
    hashtags:         d.hashtags || '',
    final_video_path: d.final_video_path,
    output_filename:  d.output_filename,
    drive_file_id:    d.drive_file_id,
    drive_video_url:  d.video_url,
    sheet_row:        d.sheet_row,
    rowIndex:         d.rowIndex,
    readyForVideoAt:  d.readyForVideoAt,
    callback_url:     null
  }};
});

const fs = require('fs');
let jobs;
try { jobs = $('Find Next Ready Job').all().map(item => item.json); }
catch (e) { jobs = $input.all().map(item => item.json); }

const url = $env.VASTAI_VIDEO_URL || "http://175.155.64.189:19486/generate";
const apiKey = $env.VASTAI_VIDEO_API_KEY;

const n8nIn = '/data/ffmpeg/input';
if (!fs.existsSync(n8nIn)) fs.mkdirSync(n8nIn, { recursive: true });

const WORKERS = ['gpu0', 'gpu1', 'gpu2', 'gpu3'];

const generateClip = async (jobId, prompt, negPrompt, index, worker) => {
  const body = { prompt, negative_prompt: negPrompt || null, width: 720, height: 1280, length: 80, worker: worker };
  let result, lastErr;
  for (let attempt = 1; attempt <= 2; attempt++) {
    try {
      console.log('Job ' + jobId + ' clip ' + index + ' -> ' + worker + ', attempt ' + attempt + '...');
      result = await this.helpers.httpRequest({
        method: 'POST',
        url,
        headers: { 'X-Api-Key': apiKey, 'Content-Type': 'application/json' },
        body,
        json: true,
        timeout: 1500000
      });
      break;
    } catch (e) {
      lastErr = e;
      if (attempt < 2) await new Promise(r => setTimeout(r, 10000));
    }
  }
  if (!result) throw new Error('Job ' + jobId + ' clip ' + index + ' (' + worker + ') failed: ' + (lastErr && lastErr.message || 'unknown'));
  if (!result.video_base64) throw new Error('Job ' + jobId + ' clip ' + index + ' missing video_base64');
  const path = n8nIn + '/' + jobId + '_clip' + index + '.webm';
  fs.writeFileSync(path, Buffer.from(result.video_base64, 'base64'));
  console.log('Job ' + jobId + ' clip ' + index + ' done in ' + result.elapsed_seconds + 's on ' + result.worker);
  return '/ffmpeg/input/' + jobId + '_clip' + index + '.webm';
};

const generateJobVideo = async (job, worker) => {
  const prompts = job.clip_prompts || [];
  const negPrompts = job.negative_prompts || [];
  // Pad to exactly 4 clips — handles old 3-clip jobs gracefully
  while (prompts.length < 4) {
    const last = prompts[prompts.length - 1];
    prompts.push(last + ', continuation shot, same subject from slightly different angle');
    negPrompts.push(negPrompts[negPrompts.length - 1] || 'text, labels, watermarks, human faces, cartoon');
    console.log('Job ' + job.job_id + ': padded clip ' + prompts.length + ' from last prompt');
  }
  if (prompts.length > 4) { prompts.length = 4; negPrompts.length = 4; }
  console.log('Job ' + job.job_id + ': 4 clip_prompts confirmed');
  const paths = [];
  for (let i = 0; i < prompts.length; i++) {
    paths.push(await generateClip(job.job_id, prompts[i], negPrompts[i], i, worker));
  }
  if (paths.length !== 4) throw new Error('Job ' + job.job_id + ': only ' + paths.length + '/4 clips generated successfully. Aborting assembly.');
  for (let i = 0; i < paths.length; i++) {
    const diskPath = paths[i].replace('/ffmpeg/input', '/data/ffmpeg/input');
    if (!fs.existsSync(diskPath)) throw new Error('Job ' + job.job_id + ': clip ' + i + ' file missing on disk: ' + paths[i]);
    const stat = fs.statSync(diskPath);
    if (stat.size < 1000) throw new Error('Job ' + job.job_id + ': clip ' + i + ' is corrupt/empty (' + stat.size + ' bytes): ' + paths[i]);
  }
  console.log('Job ' + job.job_id + ': all 4 clips verified on disk.');
  return paths;
};

console.log('Processing ' + jobs.length + ' job(s) in parallel, one dedicated GPU each (clips sequential per job)...');
const allPaths = await Promise.all(
  jobs.map((job, i) => generateJobVideo(job, WORKERS[i % WORKERS.length]))
);
console.log('All ' + jobs.length + ' job(s) complete.');

return jobs.map((job, i) => ({ json: {
  ...job,
  video_paths: allPaths[i],
  clips_count: allPaths[i].length
}}));

const res = $input.first().json;
const rows = res.values || [];
const todayKey = new Date().toISOString().slice(0, 10);
const dailyCap = 12;
const STUCK_MS = 30 * 60 * 1000;
const now = Date.now();

const renderedToday = rows.filter(r => {
  const status = (r[3] || '').toUpperCase().trim();
  const readyAt = r[10] || '';
  return (status === 'READY_TO_PUBLISH' || status === 'PUBLISHING' || status === 'PUBLISHED') && readyAt.startsWith(todayKey);
}).length;

if (renderedToday >= dailyCap) {
  return [{ json: { stop: true, reason: 'DAILY_CAP_REACHED', renderedToday, dailyCap } }];
}

const allRows = rows.map((r, i) => ({
  rowIndex: i + 2,
  status: (r[3] || '').toUpperCase().trim(),
  job_id: r[0] || '',
  topic: r[1] || '',
  title: r[2] || '',
  payloadJson: r[4] || '',
  hashtags: r[7] || '',
  sheetRow: r[8] || '',
  readyForVideoAt: r[9] || ''
}));

let ready = allRows.filter(r => r.status === 'READY_FOR_VIDEO');
if (ready.length === 0) {
  ready = allRows.filter(r => {
    if (r.status !== 'IN_PROGRESS') return false;
    const ts = r.readyForVideoAt ? new Date(r.readyForVideoAt).getTime() : 0;
    return ts > 0 && (now - ts) > STUCK_MS;
  });
  if (ready.length > 0) console.log('Recovering ' + ready.length + ' stuck IN_PROGRESS job(s)');
}

if (ready.length === 0) {
  return [{ json: { stop: true, reason: 'NO_READY_JOBS', renderedToday, dailyCap } }];
}

const BATCH_SIZE = 4;
const batch = ready.slice(0, BATCH_SIZE);
console.log('Picked ' + batch.length + ' job(s) for this batch: ' + batch.map(j => j.job_id).join(', '));

return batch.map(job => {
  let payload = {};
  try { payload = JSON.parse(job.payloadJson); } catch (e) {}
  return { json: {
    stop: false,
    rowIndex: job.rowIndex,
    job_id: job.job_id,
    topic: job.topic,
    title: job.title,
    hashtags: job.hashtags,
    sheet_row: job.sheetRow,
    readyForVideoAt: job.readyForVideoAt,
    narration: payload.narration,
    clip_prompts: payload.clip_prompts,
    audio_path: payload.audio_path,
    subs_path: payload.subs_path,
    audio_duration: payload.audio_duration,
    subtitle_chunks: payload.subtitle_chunks,
    word_timings: payload.word_timings,
    bgm_path: payload.bgm_path,
    negative_prompts: payload.negative_prompts,
    highlight_keywords: payload.highlight_keywords,
    scenes: payload.scenes || [],
    start_time: Date.now()
  }};
});

const data = $input.first().json;
console.log('Stage 2 daily run idle. Reason: ' + data.reason + (data.renderedToday !== undefined ? '. Rendered today: ' + data.renderedToday + '/' + data.dailyCap : ''));
return [{ json: { summary: 'stage2_idle', ...data } }];

const items = $input.all();
console.log('Batch complete: ' + items.length + ' video(s) marked READY_TO_PUBLISH.');
return [{ json: { batchSize: items.length, jobIds: items.map(i => i.json.job_id || i.json.rowIndex) } }];
